mapper.select:
SELECT r.reservation_id, p.title, u.name, u.phone, s.start_time, s.end_time, r.status FROM workshop w JOIN program p ON w.workshop_id = p.workshop_id JOIN schedule s ON p.program_id = s.program_id JOIN reservation r ON s.schedule_id = r.schedule_id JOIN user u ON r.user_id = u.user_id
p.program_id = #{programId}
w.workshop_id = #{workshopId}

mapper.update:
UPDATE reservation
SET status = #{status}
WHERE reservation_id = #{reservationId}
